mapper.select:
SELECT * FROM `user`
AND (username LIKE CONCAT('%', #{keyword}, '%') OR real_name LIKE CONCAT('%', #{keyword}, '%') OR phone LIKE CONCAT('%', #{keyword}, '%'))
ORDER BY create_time DESC LIMIT #{offset}, #{limit}

mapper.update:
UPDATE `user`
real_name = #{realName}, phone = #{phone}, email = #{email}, avatar = #{avatar}, role = #{role}, status = #{status}, password = #{password},
WHERE id = #{id}

mapper.select:
SELECT MONTH(create_time) AS month, COUNT(*) AS count
FROM `user` WHERE YEAR(create_time) = #{year}
GROUP BY MONTH(create_time) ORDER BY month
